    12→
    13→const PointsDetailBase: FC<ScreenProps<'PointsDetail'>> = ({
    14→  navigation,
    15→  route,
    16→}) => {
    17→  const hasFocused = useRef(false);
    18→  const modalizeRef = useRef<PropsModalizeRef>(null);
    19→  
    20→  useFocusEffect(
    21→    useCallback(() => {
    22→      if (!hasFocused.current) {
    23→        eventScreenViewV3(  
    24→          'detalhe_extrato_hub_recompensas',
    25→          'hub_recompensas_spmais',
    26→          'monetizacao',
    27→          {
    28→            location_1: 'monetizacao',
    29→            location_2: 'hub_recompensas_spmais',
    30→            location_3: 'detalhe_extrato_hub_recompensas',
    31→          });
    32→          hasFocused.current = true;
    33→        }
    34→        return () => {
    35→          hasFocused.current = false;
    36→        };
    37→      }, [])
    38→    )
    39→
    40→  const handleGoBack = () => {
    41→    navigation.goBack();
    42→  };
    43→
    44→  const handleOpenReportProblem = () => {
    45→    eventSelectContent({
    46→      content_type: 'cta',
    47→      content_id: 'relatar_problema',
    48→      location_1: 'monetizacao',
    49→      location_2: 'hub_recompensas_spmais',
    50→      location_3: 'detalhe_extrato_hub_recompensas',
    51→    });
    52→   
    53→    eventModalView({
    54→      content_id: 'contato_telefones',
    55→      location_1: 'monetizacao',
    56→      location_2: 'hub_recompensas_spmais',
    57→      location_3: 'detalhe_extrato_hub_recompensas',
    58→    });
    59→
    60→    modalizeRef.current?.open?.();
    61→  };
    62→
    63→  const handleCloseReportProblem = () => {
    64→    modalizeRef.current?.close?.();
    65→  };
    66→
    67→  const transaction = route.params?.transaction;
    68→
    69→  if (!transaction) {
    70→    return null;
    71→  }
    72→
    73→  return (
    74→    <PointsDetailView
    75→      handleGoBack={handleGoBack}
    76→      transaction={transaction}
    77→      modalizeRef={modalizeRef}
    78→      handleOpenReportProblem={handleOpenReportProblem}
    79→      handleCloseReportProblem={handleCloseReportProblem}
    80→    />
    81→  );
    82→};
