    85→  return {
    86→    fintechPointsReducer: pointsReducer,
    87→  };
    88→};
    89→
    90→export const mapDispatchToProps = (dispatch: Dispatch) => {
    91→  return bindActionCreators(
    92→    {
    93→      ...PointsActions,
    94→    },
    95→    dispatch,
    96→  );
    97→};
    98→
    99→export default connect(mapStateToProps, mapDispatchToProps)(PointsDetailBase);
