     4→
     5→export type ExtractRequestType = 'Credito' | 'Debito' | 'Expirado' | 'Resgate';
     6→
     7→export interface ExtractRequestDto {
     8→  participantId: string;
     9→  page?: number;
    10→  pageSize?: number;
    11→  type?: ExtractRequestType;
    12→}
    13→
    14→export interface TransactionDto {
    15→  id: string;
    16→  date: string;
    17→  description: string;
    18→  type: string;
    19→  amount: number;
    20→  icon: string;
    21→  status?: string;
    22→  origination?: string;
    23→}
    24→
    25→interface PaginationDto {
    26→  page: number;
    27→  pageSize: number;
    28→  total: number;
    29→  totalPages: number;
    30→}
    31→
    32→export interface PointsExtractApiResponse {
    33→  data: {
    34→    transactions: TransactionDto[];
    35→  };
    36→  pagination: PaginationDto;
    37→  status: {
    38→    returnCode: number;
    39→    message: string;
    40→  };
    41→}
    42→
    43→interface PointsBalanceApiResponse {
    44→  data: { points?: number };
    45→  status: {
    46→    returnCode?: number;
    47→    codigoRetorno?: number;
    48→    message?: string;
    49→  };
    50→}
    51→
    52→function buildExtractRequestPayload(
    53→  payload: ExtractRequestDto,
    54→): ExtractRequestDto {
    55→  return {
    56→    participantId: payload.participantId,
    57→    page: payload.page ?? EXTRACT_CONSTANTS.DEFAULT_PAGE,
    58→    pageSize: payload.pageSize ?? EXTRACT_CONSTANTS.DEFAULT_PAGE_SIZE,
    59→    ...(payload.type ? { type: payload.type } : {}),
    60→  };
    61→}
    62→
    63→export async function getPointsExtractApi(
    64→  payload: ExtractRequestDto,
    65→): Promise<AxiosResponse<PointsExtractApiResponse>> {
    66→  const requestPayload = buildExtractRequestPayload(payload);
    67→
    68→  return api.post<PointsExtractApiResponse>(
    69→    'fintech/v1/rewardProgram/extract',
    70→    requestPayload,
    71→  );
    72→}
    73→
    74→export async function getPointsBalanceApi(): Promise<
    75→  AxiosResponse<PointsBalanceApiResponse>
    76→> {
    77→  return api.get<PointsBalanceApiResponse>(
    78→    'fintech/v1/rewardProgram/balance',
    79→    {},
    80→  );
    81→}
