    40→  const { orderDetailActions, orderDetail } = useRootStore.getState();
    41→
    42→  const isDifferentTransaction =
    43→    orderDetail.transactionId !== payload.transactionId;
    44→  const isAlreadyLoading = orderDetail.status === OrderDetailStatus.LOADING;
    45→
    46→  if (isAlreadyLoading && !isDifferentTransaction) {
    47→    return;
    48→  }
    49→
    50→  if (isDifferentTransaction) {
    51→    orderDetailActions.reset();
    52→  }
    53→
